from agent import *from models.products import *import reXCAT = ["Hem", "Varumärken", "REA"]def remove_emoji(string):    emoji_pattern = re.compile("["                               u"\U0001F600-\U0001F64F"  # emoticons                               u"\U0001F300-\U0001F5FF"  # symbols & pictographs                               u"\U0001F680-\U0001F6FF"  # transport & map symbols                               u"\U0001F1E0-\U0001F1FF"  # flags (iOS)                               u"\U00002500-\U00002BEF"  # chinese char                               u"\U00002702-\U000027B0"                               u"\U00002702-\U000027B0"                               u"\U000024C2-\U0001F251"                               u"\U0001f926-\U0001f937"                               u"\U00010000-\U0010ffff"                               u"\u2640-\u2642"                               u"\u2600-\u2B55"                               u"\u200d"                               u"\u23cf"                               u"\u23e9"                               u"\u231a"                               u"\ufe0f"  # dingbats                               u"\u3030"                               "]+", flags=re.UNICODE)    return emoji_pattern.sub(r'', string)def run(context, session):    session.sessionbreakers = [SessionBreak(max_requests=3000)]    session.queue(Request("https://you.se/", use='curl', max_age=0), process_frontpage, dict())def process_frontpage(data, context, session):    print(data.content)    cats = data.xpath("//div[@id='menu']/ul/li")    for cat in cats:        name = cat.xpath("a/text()").string()        url = cat.xpath("a/@href").string()        if name in XCAT:            continue        subcats = cat.xpath("div/ul/li/a")        if not subcats:            session.queue(Request(url), process_brandlist, dict(cat=name, prods_url=url))        for subcat in subcats:            subcat_name = subcat.xpath("text()").string()            url = subcat.xpath("@href").string()            session.queue(Request(url), process_brandlist, dict(cat=name+'|'+subcat_name, prods_url=url))def process_brandlist(data, context, session):    brands = data.xpath("//ul[@class='filter_grouper']/li[div[text()='Varumärke']]//ul/li")    for brand in brands:        name = brand.xpath("text()").string()        id = brand.xpath("@id").string()        url = context["prods_url"] + "?forcefiltersupdate=true&checkedfilters%5B%5D=" + id        session.queue(Request(url), process_prodlist, dict(context, brand=name))def process_prodlist(data, context, session):    prods = data.xpath("//div[@class='list-item'][descendant::span[@data-original-title][not(contains(@data-original-title, ' 0 recensioner'))]]")    for prod in prods:        product = Product()        product.name = prod.xpath(".//h3[@class='wname']/a/@title").string()        product.url = prod.xpath(".//h3[@class='wname']/a/@href").string()        product.ssid = prod.xpath(".//a[contains(@onclick, 'addToWishList')]/@onclick").string().split("'")[-2]        product.sku = product.ssid        product.category = context["cat"]        product.manufacturer = context["brand"]        revs_url = "https://you.se/index.php?route=product/product/review&product_id=" + product.ssid + "&page=1"        session.queue(Request(revs_url), process_reviews, dict(product=product))    next_page = data.xpath("//a[text()='>']/@href").string()    if next_page:        session.queue(Request(next_page), process_prodlist, dict(context))def process_reviews(data, context, session):    product = context["product"]    revs = data.xpath("//tbody/tr")    for rev in revs:        review = Review()        review.type = "user"        review.date = rev.xpath("td/i/text()").string()        review.url = product.url        author = rev.xpath("td[@class='user']/text()").string()        if author:            review.authors.append(Person(name=author, ssid=author))        overall = int(rev.xpath("td/span[contains(@class, 'rating')]/@class").string().split(' ')[-1][-1])        if overall:            review.grades.append(Grade(type="overall", value=overall, best=5))        excerpt = rev.xpath("td[@class='text']//text()").string(multiple=True)        if excerpt:            excerpt = remove_emoji(excerpt).strip('*+=-_\n ')            if excerpt:                review.add_property(type="excerpt", value=excerpt)                review.ssid = review.digest() if author else review.digest(excerpt)                product.reviews.append(review)    next_page = data.xpath("//a[text()='>']/@href").string()    if next_page:        session.do(Request(next_page), process_reviews, dict(product=product))    elif product.reviews:        session.emit(product)